// RegisterTools registers all API operations as MCP tools.
func RegisterTools(s *server.MCPServer) {
	s.AddTool(
		mcplib.NewTool("captures_submit",
			mcplib.WithDescription("Submit a URL for archiving. Synchronous, can take 30-120 seconds. Returns the memento URL in Refresh/Location header. Returns memento."),
			mcplib.WithString("url", mcplib.Required(), mcplib.Description("URL to archive")),
			mcplib.WithString("anyway", mcplib.Description("Set to 1 to force a fresh capture even if a recent snapshot exists")),
		),
		makeAPIHandler("GET", "/submit/", []string{}),
	)
	s.AddTool(
		mcplib.NewTool("feeds_recent",
			mcplib.WithDescription("Global RSS feed of recently archived URLs across all users Returns array of feed_item."),
		),
		makeAPIHandler("GET", "/rss", []string{}),
	)
	s.AddTool(
		mcplib.NewTool("feeds_search",
			mcplib.WithDescription("Search archived pages by query. Returns HTML; must be parsed. Returns array of search_result."),
			mcplib.WithString("q", mcplib.Required(), mcplib.Description("Search query")),
		),
		makeAPIHandler("GET", "/search/", []string{"q"}),
	)
	s.AddTool(
		mcplib.NewTool("snapshots_newest",
			mcplib.WithDescription("Get the most recent snapshot for a URL. Redirects to the latest memento. Returns memento."),
			mcplib.WithString("url", mcplib.Required(), mcplib.Description("The original URL")),
		),
		makeAPIHandler("GET", "/newest/{url}", []string{"url"}),
	)
	s.AddTool(
		mcplib.NewTool("snapshots_timegate",
			mcplib.WithDescription("Find the best snapshot for a URL. Returns 302 with Location header pointing at the memento. Memento Protocol compliant. Returns memento."),
			mcplib.WithString("url", mcplib.Required(), mcplib.Description("The original URL to look up. URL-encode special characters.")),
		),
		makeAPIHandler("GET", "/timegate/{url}", []string{"url"}),
	)
	s.AddTool(
		mcplib.NewTool("snapshots_timemap",
			mcplib.WithDescription("Get all known snapshots for a URL as a Memento link-format list. Returns text/application/link-format. Returns array of memento."),
			mcplib.WithString("url", mcplib.Required(), mcplib.Description("The original URL to list snapshots for")),
		),
		makeAPIHandler("GET", "/timemap/{url}", []string{"url"}),
	)
	// Sync tool — populates local database for offline search and sql queries
	s.AddTool(
		mcplib.NewTool("sync",
			mcplib.WithDescription("Sync API data to local SQLite database. Run this before using search or sql tools. Supports incremental sync."),
			mcplib.WithString("resources", mcplib.Description("Comma-separated resource types to sync (omit for all)")),
			mcplib.WithString("since", mcplib.Description("Incremental sync since duration (e.g. 7d, 24h, 1w)")),
			mcplib.WithBoolean("full", mcplib.Description("Full resync ignoring checkpoints")),
		),
		handleSync,
	)
	// SQL tool — ad-hoc analysis on synced data without API calls
	s.AddTool(
		mcplib.NewTool("sql",
			mcplib.WithDescription("Run read-only SQL against local database. Use for ad-hoc analysis, aggregations, and joins across synced resources. Requires sync first."),
			mcplib.WithString("query", mcplib.Required(), mcplib.Description("SQL query (SELECT only). Tables match resource names.")),
		),
		handleSQL,
	)

	// Context tool — front-loaded domain knowledge for agents.
	// Call this first to understand the API taxonomy, query patterns, and capabilities.
	s.AddTool(
		mcplib.NewTool("context",
			mcplib.WithDescription("Get API domain context: resource taxonomy, auth requirements, query tips, and unique capabilities. Call this first."),
		),
		handleContext,
	)
}

// makeAPIHandler creates a generic MCP tool handler for an API endpoint.
func makeAPIHandler(method, pathTemplate string, positionalParams []string) server.ToolHandlerFunc {
	return func(ctx context.Context, req mcplib.CallToolRequest) (*mcplib.CallToolResult, error) {
		c, err := newMCPClient()
		if err != nil {
			return mcplib.NewToolResultError(err.Error()), nil
		}

		// Build path by substituting positional params
		path := pathTemplate
		pathParams := make(map[string]bool, len(positionalParams))
		for _, p := range positionalParams {
			placeholder := "{" + p + "}"
			if !strings.Contains(pathTemplate, placeholder) {
				continue
			}
			pathParams[p] = true
			if v, ok := req.Params.Arguments[p]; ok {
				path = strings.Replace(path, placeholder, fmt.Sprintf("%v", v), 1)
			}
		}

		// Collect non-path params as query params
		params := make(map[string]string)
		for k, v := range req.Params.Arguments {
			if !pathParams[k] {
				params[k] = fmt.Sprintf("%v", v)
			}
		}

		var data json.RawMessage
		switch method {
		case "GET":
			data, err = c.Get(path, params)
		case "POST":
			body, _ := json.Marshal(req.Params.Arguments)
			data, _, err = c.Post(path, body)
		case "PUT":
			body, _ := json.Marshal(req.Params.Arguments)
			data, _, err = c.Put(path, body)
		case "PATCH":
			body, _ := json.Marshal(req.Params.Arguments)
			data, _, err = c.Patch(path, body)
		case "DELETE":
			data, _, err = c.Delete(path)
		default:
			return mcplib.NewToolResultError("unsupported method: " + method), nil
		}

		if err != nil {
			msg := err.Error()
			switch {
			case strings.Contains(msg, "HTTP 409"):
				return mcplib.NewToolResultText("already exists (no-op)"), nil
			case strings.Contains(msg, "HTTP 401"):
				return mcplib.NewToolResultError("authentication failed: " + msg +
					"\nhint: check your API credentials." +
					"\n      Run 'archive-is-pp-cli doctor' to check auth status."), nil
			case strings.Contains(msg, "HTTP 403"):
				return mcplib.NewToolResultError("permission denied: " + msg +
					"\nhint: your credentials are valid but lack access to this resource." +
					"\n      Run 'archive-is-pp-cli doctor' to check auth status."), nil
			case strings.Contains(msg, "HTTP 404"):
				if method == "DELETE" {
					return mcplib.NewToolResultText("already deleted (no-op)"), nil
				}
				return mcplib.NewToolResultError("not found: " + msg), nil
			case strings.Contains(msg, "HTTP 429"):
				return mcplib.NewToolResultError("rate limited: " + msg), nil
			default:
				return mcplib.NewToolResultError(msg), nil
			}
		}

		// For GET responses, wrap bare arrays with count metadata
		if method == "GET" {
			trimmed := strings.TrimSpace(string(data))
			if len(trimmed) > 0 && trimmed[0] == '[' {
				var items []json.RawMessage
				if json.Unmarshal(data, &items) == nil {
					wrapped := map[string]any{
						"count": len(items),
						"items": items,
					}
					out, _ := json.Marshal(wrapped)
					return mcplib.NewToolResultText(string(out)), nil
				}
			}
		}
		return mcplib.NewToolResultText(string(data)), nil
	}
}

func newMCPClient() (*client.Client, error) {
	home, _ := os.UserHomeDir()
	cfgPath := filepath.Join(home, ".config", "archive-is-pp-cli", "config.toml")
	cfg, err := config.Load(cfgPath)
	if err != nil {
		return nil, fmt.Errorf("loading config: %w", err)
	}
	c := client.New(cfg, 30*time.Second, 0)
	// Agents calling through MCP need fresh data every call. The on-disk
	// response cache survives across MCP server invocations, so a DELETE/PATCH
	// followed by a GET would otherwise return the pre-mutation snapshot for up
	// to the cache TTL. Skip the cache for the MCP path; the interactive CLI
	// constructs its own client and is unaffected.
	c.NoCache = true
	return c, nil
}

func dbPath() string {
	home, _ := os.UserHomeDir()
	return filepath.Join(home, ".local", "share", "archive-is-pp-cli", "data.db")
}

